import{_ as e,o as a,c as h,f as t}from"./app-4ce8496b.js";const d={},i=t('<ul><li><em>语气</em>: <ul><li><strong>陈述语气</strong>: 陈述事实</li><li><strong>祈使语气</strong>: 用于表达命令或请求</li><li><strong>虚拟语气</strong>: 用于表达说话人的主观愿望或假设，这些愿望或假设不一定是事实，或与事实相反。虚拟语气是通过改变谓语动词形式来体现的。</li></ul></li></ul><h2 id="一-if引导的非真实条件句" tabindex="-1"><a class="header-anchor" href="#一-if引导的非真实条件句" aria-hidden="true">#</a> 一,if引导的非真实条件句</h2><h5 id="_1-if-i-were-a-boy-i-would-be-a-better-man" tabindex="-1"><a class="header-anchor" href="#_1-if-i-were-a-boy-i-would-be-a-better-man" aria-hidden="true">#</a> 1. If I were a boy, I would be a better man.</h5><h5 id="_2-if-she-had-arrived-last-night-she-would-have-gone-to-the-party" tabindex="-1"><a class="header-anchor" href="#_2-if-she-had-arrived-last-night-she-would-have-gone-to-the-party" aria-hidden="true">#</a> 2. If she had arrived last night, she would have gone to the party.</h5><h5 id="_3-if-you-came-tomorrow-i-would-give-you-a-big-surprise" tabindex="-1"><a class="header-anchor" href="#_3-if-you-came-tomorrow-i-would-give-you-a-big-surprise" aria-hidden="true">#</a> 3. If you came tomorrow, I would give you a big surprise.</h5><h3 id="_1-动词形式" tabindex="-1"><a class="header-anchor" href="#_1-动词形式" aria-hidden="true">#</a> 1.动词形式</h3><table><thead><tr><th>时间</th><th>if从句</th><th>主句</th></tr></thead><tbody><tr><td>现在</td><td>did/were</td><td>would/should/could/might + do</td></tr><tr><td>过去</td><td>had done</td><td>would/should/could/might + have done</td></tr><tr><td>过去</td><td>did/were,were to do,should do</td><td>would/should/could/might + do</td></tr></tbody></table><h5 id="_1-if-there-were-no-plants-we-would-have-no-animals-and-meat" tabindex="-1"><a class="header-anchor" href="#_1-if-there-were-no-plants-we-would-have-no-animals-and-meat" aria-hidden="true">#</a> 1. If there <mark>were</mark> no plants, we would have no animals and meat.</h5><h5 id="_2-it-would-be-very-nice-if-it-were-possible" tabindex="-1"><a class="header-anchor" href="#_2-it-would-be-very-nice-if-it-were-possible" aria-hidden="true">#</a> 2. It <mark>would be</mark> very nice if it were possible.</h5><h5 id="_3-if-you-had-come-five-minutes-earlier-you-would-have-met-the-famous-star" tabindex="-1"><a class="header-anchor" href="#_3-if-you-had-come-five-minutes-earlier-you-would-have-met-the-famous-star" aria-hidden="true">#</a> 3. If you <mark>had come</mark> five minutes earlier, you would have met the famous star.</h5><h5 id="_4-i-would-go-to-the-party-with-you-if-i-didn-t-need-to-attend-the-meeting" tabindex="-1"><a class="header-anchor" href="#_4-i-would-go-to-the-party-with-you-if-i-didn-t-need-to-attend-the-meeting" aria-hidden="true">#</a> 4. I <mark>would go</mark> to the party with you if I didn&#39;t need to attend the meeting.</h5><h5 id="_5-if-he-had-followed-my-advice-he-would-be-better-now" tabindex="-1"><a class="header-anchor" href="#_5-if-he-had-followed-my-advice-he-would-be-better-now" aria-hidden="true">#</a> 5. If he had followed my advice, he <mark>would be</mark> better now.</h5><h3 id="_2-混合时间虚拟-错综时间" tabindex="-1"><a class="header-anchor" href="#_2-混合时间虚拟-错综时间" aria-hidden="true">#</a> 2.混合时间虚拟（错综时间）</h3><h4 id="当从句和主句动作发生时间不一致-则主从句分别采用对应的动词形式。-注意时间词" tabindex="-1"><a class="header-anchor" href="#当从句和主句动作发生时间不一致-则主从句分别采用对应的动词形式。-注意时间词" aria-hidden="true">#</a> 当从句和主句动作发生时间不一致，则主从句分别采用对应的动词形式。(注意时间词)</h4><h5 id="if-you-didn-t-watch-the-movie-last-night-you-wouldn-t-be-so-sleepy" tabindex="-1"><a class="header-anchor" href="#if-you-didn-t-watch-the-movie-last-night-you-wouldn-t-be-so-sleepy" aria-hidden="true">#</a> If you didn&#39;t watch the movie last night, you wouldn&#39;t be so sleepy.</h5><h3 id="_3-虚拟倒装" tabindex="-1"><a class="header-anchor" href="#_3-虚拟倒装" aria-hidden="true">#</a> 3.虚拟倒装</h3><h4 id="在if引导的非真实条件句中-可以把were-had-助动词-should提到主语之前-同时省略if。" tabindex="-1"><a class="header-anchor" href="#在if引导的非真实条件句中-可以把were-had-助动词-should提到主语之前-同时省略if。" aria-hidden="true">#</a> 在if引导的非真实条件句中，可以把were/had(助动词)/should提到主语之前，同时省略if。</h4><h4 id="解题技巧-把句子还原" tabindex="-1"><a class="header-anchor" href="#解题技巧-把句子还原" aria-hidden="true">#</a> <mark>解题技巧:把句子还原.</mark></h4><h5 id="if-i-were-a-boy-i-would-be-a-better-man-were-i-a-boy-i-would-be-a-better-man" tabindex="-1"><a class="header-anchor" href="#if-i-were-a-boy-i-would-be-a-better-man-were-i-a-boy-i-would-be-a-better-man" aria-hidden="true">#</a> If I were a boy, I would be a better man.Were I a boy, I would be a better man.</h5><h5 id="were-i-a-boy-i-would-be-a-better-man-were-i-a-boy-i-would-be-a-better-man" tabindex="-1"><a class="header-anchor" href="#were-i-a-boy-i-would-be-a-better-man-were-i-a-boy-i-would-be-a-better-man" aria-hidden="true">#</a> -&gt;Were I a boy, I would be a better man.Were I a boy, I would be a better man.</h5><h5 id="if-bob-had-known-the-truth-he-wouldn-t-have-helped-her-at-all" tabindex="-1"><a class="header-anchor" href="#if-bob-had-known-the-truth-he-wouldn-t-have-helped-her-at-all" aria-hidden="true">#</a> If Bob had known the truth, he wouldn&#39;t have helped her at all.</h5><h3 id="_4-含蓄虚拟" tabindex="-1"><a class="header-anchor" href="#_4-含蓄虚拟" aria-hidden="true">#</a> 4.含蓄虚拟</h3><h4 id="without-but-for-otherwise-or替代if引导的从句-主句动词形势同if" tabindex="-1"><a class="header-anchor" href="#without-but-for-otherwise-or替代if引导的从句-主句动词形势同if" aria-hidden="true">#</a> without,but for,otherwise,or替代if引导的从句,主句动词形势同if</h4><h5 id="without-plants-wew-would-have-no-animals-and-meat" tabindex="-1"><a class="header-anchor" href="#without-plants-wew-would-have-no-animals-and-meat" aria-hidden="true">#</a> Without plants wew would have no animals and meat</h5><h5 id="but-for-your-help-we-couldn-t-have-finished-the-task-as-promised" tabindex="-1"><a class="header-anchor" href="#but-for-your-help-we-couldn-t-have-finished-the-task-as-promised" aria-hidden="true">#</a> But for your help ,we couldn&#39;t have finished the task as promised</h5><h2 id="二-should-do-形式虚拟形式" tabindex="-1"><a class="header-anchor" href="#二-should-do-形式虚拟形式" aria-hidden="true">#</a> 二, <mark>(should)</mark> do 形式虚拟形式</h2><h5 id="my-mon-required-that-them-room-should-be-cleaned-every-day" tabindex="-1"><a class="header-anchor" href="#my-mon-required-that-them-room-should-be-cleaned-every-day" aria-hidden="true">#</a> My mon required that them room (should) be cleaned every day</h5><h3 id="_1-当主句中含有命令、建议、请求-要求、决定等含义的词-区分词性-所接从句谓语动词用-should-do-be-done。" tabindex="-1"><a class="header-anchor" href="#_1-当主句中含有命令、建议、请求-要求、决定等含义的词-区分词性-所接从句谓语动词用-should-do-be-done。" aria-hidden="true">#</a> 1. 当主句中含有命令、建议、请求/要求、决定等含义的词（区分词性），所接从句谓语动词用 (should) do/be done。</h3><h5 id="命令-order-command" tabindex="-1"><a class="header-anchor" href="#命令-order-command" aria-hidden="true">#</a> 命令: order,command</h5><h4 id="建议-suggest-advise-propose-recommend" tabindex="-1"><a class="header-anchor" href="#建议-suggest-advise-propose-recommend" aria-hidden="true">#</a> 建议: suggest, advise, propose, recommend</h4><h4 id="请求-要求-demand-require-request-insist-desire-ask-prefer" tabindex="-1"><a class="header-anchor" href="#请求-要求-demand-require-request-insist-desire-ask-prefer" aria-hidden="true">#</a> 请求/要求: demand, require, request, insist, desire, ask, prefer</h4><h4 id="决定-decide-determine" tabindex="-1"><a class="header-anchor" href="#决定-decide-determine" aria-hidden="true">#</a> 决定: decide, determine</h4><h4 id="my-suggestion-is-that-you-should-learn-from-the-very-start" tabindex="-1"><a class="header-anchor" href="#my-suggestion-is-that-you-should-learn-from-the-very-start" aria-hidden="true">#</a> My suggestion is that you should learn from the very start</h4><h4 id="it-is-suggestion-that-the-meeting-should-be-delayed-to-next-friday" tabindex="-1"><a class="header-anchor" href="#it-is-suggestion-that-the-meeting-should-be-delayed-to-next-friday" aria-hidden="true">#</a> It is suggestion that the meeting should be delayed to next Friday</h4><h3 id="_2-在it-is-adj-done-n-that-从句-从句谓语动词也可以用-should-do-be-done形式" tabindex="-1"><a class="header-anchor" href="#_2-在it-is-adj-done-n-that-从句-从句谓语动词也可以用-should-do-be-done形式" aria-hidden="true">#</a> 2.在It is +adj/done/n.+that +从句，从句谓语动词也可以用(should) do/be done形式</h3><h5 id="关键词" tabindex="-1"><a class="header-anchor" href="#关键词" aria-hidden="true">#</a> 关键词</h5><h4 id="important-vital-crucial-necessary-essential-urgent-natural-strange-pity-shame" tabindex="-1"><a class="header-anchor" href="#important-vital-crucial-necessary-essential-urgent-natural-strange-pity-shame" aria-hidden="true">#</a> <mark>important,vital,crucial,necessary,essential,urgent,natural,strange,pity,shame</mark></h4><h4 id="it-is-essential-that-you-should-have-some-work-experience" tabindex="-1"><a class="header-anchor" href="#it-is-essential-that-you-should-have-some-work-experience" aria-hidden="true">#</a> It is essential that you should have some work experience</h4><h3 id="it-is-a-pity-that-should-lose-the-game" tabindex="-1"><a class="header-anchor" href="#it-is-a-pity-that-should-lose-the-game" aria-hidden="true">#</a> It is a pity that should lose the game</h3><h3 id="_3-在-in-case-、-lest-、-for-fear-that-以防-以免-引导的从句中-动词形式通常使用-should-do-或-be-done。" tabindex="-1"><a class="header-anchor" href="#_3-在-in-case-、-lest-、-for-fear-that-以防-以免-引导的从句中-动词形式通常使用-should-do-或-be-done。" aria-hidden="true">#</a> 3. 在 in case 、 lest 、 for fear that （以防，以免）引导的从句中，动词形式通常使用 (should) do 或 be done。</h3><ul><li><p><strong>在情况下 (in case)</strong>:</p><ul><li>句子: Take an umbrella with you in case it (should) rain.</li></ul></li><li><p><strong>以免 (lest)</strong>:</p><ul><li>句子: I didn&#39;t make any noise lest I (should) disturb you.</li></ul></li><li><p><strong>以防 (for fear that)</strong>:</p><ul><li>句子: I didn&#39;t make any noise for fear that I (should) disturb you.</li></ul></li></ul><h2 id="三-特殊虚拟" tabindex="-1"><a class="header-anchor" href="#三-特殊虚拟" aria-hidden="true">#</a> 三,特殊虚拟</h2><h3 id="_1-固定句型-it-is-about-high-time-that-主语-did-该是做-的时候了" tabindex="-1"><a class="header-anchor" href="#_1-固定句型-it-is-about-high-time-that-主语-did-该是做-的时候了" aria-hidden="true">#</a> 1.固定句型:It is (about/high) time (that)+主语+did.....“该是做...的时候了”</h3><h4 id="_1-it-is-high-time-that-we-took-measures-to-protect-the-environment" tabindex="-1"><a class="header-anchor" href="#_1-it-is-high-time-that-we-took-measures-to-protect-the-environment" aria-hidden="true">#</a> 1. It is high time that we took measures to protect the environment.</h4><h4 id="_2-it-is-time-we-bought-a-new-computer" tabindex="-1"><a class="header-anchor" href="#_2-it-is-time-we-bought-a-new-computer" aria-hidden="true">#</a> 2. It is time we bought a new computer.</h4><h3 id="_2-wish-if-only-要是-就好了-as-if-as-though-好像-would-rather-would-sooner-宁愿-等引导的从句通常使用虚拟语气。" tabindex="-1"><a class="header-anchor" href="#_2-wish-if-only-要是-就好了-as-if-as-though-好像-would-rather-would-sooner-宁愿-等引导的从句通常使用虚拟语气。" aria-hidden="true">#</a> 2. wish, if only (要是...就好了), as if, as though (好像), would rather, would sooner (宁愿) 等引导的从句通常使用虚拟语气。</h3><table><thead><tr><th>时间</th><th>好像,要是 + 从句</th><th>宁愿 + 从句</th></tr></thead><tbody><tr><td>现在</td><td>did/were</td><td>did/were</td></tr><tr><td>过去</td><td>had done</td><td>had done</td></tr><tr><td>将来</td><td>would/could do</td><td>did/were</td></tr></tbody></table><h4 id="_1-i-d-rather-you-went-tomorrow" tabindex="-1"><a class="header-anchor" href="#_1-i-d-rather-you-went-tomorrow" aria-hidden="true">#</a> 1.I&#39;d rather you went tomorrow.</h4><h4 id="_2-i-wish-i-had-studied-harder-three-years-ago" tabindex="-1"><a class="header-anchor" href="#_2-i-wish-i-had-studied-harder-three-years-ago" aria-hidden="true">#</a> 2.I wish I had studied harder three years ago.</h4><h4 id="_3-i-wish-that-someday-i-will-live-on-the-moon" tabindex="-1"><a class="header-anchor" href="#_3-i-wish-that-someday-i-will-live-on-the-moon" aria-hidden="true">#</a> 3.I wish that someday I will live on the moon.</h4><h4 id="_4-if-only-i-had-taken-his-advice-i-wouldn-t-have-made-such-a-mistake" tabindex="-1"><a class="header-anchor" href="#_4-if-only-i-had-taken-his-advice-i-wouldn-t-have-made-such-a-mistake" aria-hidden="true">#</a> 4.If only I had taken his advice, I wouldn&#39;t have made such a mistake.</h4><h4 id="_5-he-looks-as-if-he-knows-me-very-much" tabindex="-1"><a class="header-anchor" href="#_5-he-looks-as-if-he-knows-me-very-much" aria-hidden="true">#</a> 5.He looks as if he knows me very much.</h4><h3 id="_3-情态动词的虚拟语气情态动词-过去式-have-done-本-实际没有" tabindex="-1"><a class="header-anchor" href="#_3-情态动词的虚拟语气情态动词-过去式-have-done-本-实际没有" aria-hidden="true">#</a> 3.情态动词的虚拟语气情态动词(过去式)+have done“本...(实际没有)</h3><h4 id="should-have-done-ought-to-have-done-本应该做某事-却没有" tabindex="-1"><a class="header-anchor" href="#should-have-done-ought-to-have-done-本应该做某事-却没有" aria-hidden="true">#</a> should have done=ought to have done 本应该做某事(却没有)</h4><h4 id="could-have-done-本来能够做某事-却没有" tabindex="-1"><a class="header-anchor" href="#could-have-done-本来能够做某事-却没有" aria-hidden="true">#</a> could have done 本来能够做某事(却没有)</h4><h4 id="might-have-done-本来可能做某事-却没有" tabindex="-1"><a class="header-anchor" href="#might-have-done-本来可能做某事-却没有" aria-hidden="true">#</a> might have done 本来可能做某事(却没有)</h4><h4 id="would-have-done-本来要做某事-却没有" tabindex="-1"><a class="header-anchor" href="#would-have-done-本来要做某事-却没有" aria-hidden="true">#</a> would have done 本来要做某事(却没有)</h4><h4 id="needn-t-have-done-本不需要做某事-却做了" tabindex="-1"><a class="header-anchor" href="#needn-t-have-done-本不需要做某事-却做了" aria-hidden="true">#</a> needn&#39;t have done 本不需要做某事(却做了)</h4><h4 id="注意-must-have-done表对过去的推测-─定-肯定-了" tabindex="-1"><a class="header-anchor" href="#注意-must-have-done表对过去的推测-─定-肯定-了" aria-hidden="true">#</a> <mark>注意:must have done表对过去的推测“─定/肯定...了”</mark></h4>',59),r=[i];function o(n,s){return a(),h("div",null,r)}const u=e(d,[["render",o],["__file","01.虚拟语气.html.vue"]]);export{u as default};
